import{_ as t,o as i,c as a,ay as e}from"./chunks/framework.-lzFfN-z.js";const l="/CoreFront-EndConcepts/asyncFirst.png",n="/CoreFront-EndConcepts/asyncSecond.png",r="/CoreFront-EndConcepts/asyncThird.png",h="/CoreFront-EndConcepts/asyncFourth.png",u=JSON.parse('{"title":"JavaScript 脚本的异步加载","description":"","frontmatter":{},"headers":[],"relativePath":"html/asyncScript.md","filePath":"html/asyncScript.md","lastUpdated":1772787829000}'),d={name:"html/asyncScript.md"};function p(o,s,c,k,g,E){return i(),a("div",null,[...s[0]||(s[0]=[e('<h1 id="javascript-脚本的异步加载" tabindex="-1">JavaScript 脚本的异步加载 <a class="header-anchor" href="#javascript-脚本的异步加载" aria-label="Permalink to &quot;JavaScript 脚本的异步加载&quot;">​</a></h1><p>异步加载脚本意味着<strong>脚本的下载过程不会阻塞 HTML 的解析</strong>。</p><h2 id="_1-脚本异步加载解决方式" tabindex="-1">1. 脚本异步加载解决方式 <a class="header-anchor" href="#_1-脚本异步加载解决方式" aria-label="Permalink to &quot;1. 脚本异步加载解决方式&quot;">​</a></h2><p><img src="'+l+'" alt="Logo" data-zoomable="true"></p><p><img src="'+n+'" alt="Logo" data-zoomable="true"></p><h3 id="_1-1-defer-属性" tabindex="-1">1.1 <code>defer</code> 属性 <a class="header-anchor" href="#_1-1-defer-属性" aria-label="Permalink to &quot;1.1 `defer` 属性&quot;">​</a></h3><p><img src="'+r+'" alt="Logo" data-zoomable="true"></p><p><code>defer</code> 属性告诉浏览器立即下载脚本，但<strong>延迟执行</strong>。</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">script</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> src</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;script1.js&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> defer</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">script</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">script</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> src</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;script2.js&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> defer</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">script</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><h4 id="_1-工作方式" tabindex="-1">1. 工作方式 <a class="header-anchor" href="#_1-工作方式" aria-label="Permalink to &quot;1. 工作方式&quot;">​</a></h4><ol><li><strong>并行下载</strong>：浏览器看到 <code>defer</code> 脚本，会立即在后台开始下载它，同时继续解析和渲染页面的其他部分。</li><li><strong>延迟执行</strong>：脚本的执行会等到整个 HTML 文档被完全解析完毕（<code>DOMContentLoaded</code> 事件触发之前）才会开始。</li><li><strong>顺序执行</strong>：如果有多个 <code>defer</code> 脚本，它们会<strong>按照在 HTML 中出现的顺序</strong>依次执行。<code>script1.js</code> 肯定会在 <code>script2.js</code> 之前执行。</li></ol><h4 id="_2-适用场景" tabindex="-1">2. 适用场景 <a class="header-anchor" href="#_2-适用场景" aria-label="Permalink to &quot;2. 适用场景&quot;">​</a></h4><ul><li>当脚本的执行依赖于整个 DOM 结构时（例如，需要操作页面上的所有元素）。</li><li>当多个脚本之间有依赖关系，需要保证执行顺序时。</li></ul><h3 id="_1-2-async-属性" tabindex="-1">1.2 <code>async</code> 属性 <a class="header-anchor" href="#_1-2-async-属性" aria-label="Permalink to &quot;1.2 `async` 属性&quot;">​</a></h3><p><img src="'+h+`" alt="Logo" data-zoomable="true"></p><p><code>async</code> 属性告诉浏览器也立即下载脚本，但下载完成后会<strong>立即执行</strong>。</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">script</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> src</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;scriptA.js&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> async</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">script</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">script</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> src</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;scriptB.js&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> async</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">script</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><h4 id="_1-工作方式-1" tabindex="-1">1. 工作方式 <a class="header-anchor" href="#_1-工作方式-1" aria-label="Permalink to &quot;1. 工作方式&quot;">​</a></h4><ol><li><strong>并行下载</strong>：和 <code>defer</code> 一样，浏览器会立即在后台下载脚本，不阻塞页面渲染。</li><li><strong>立即执行</strong>：一旦脚本下载完成，浏览器会<strong>立即暂停 HTML 解析</strong>，执行该脚本。执行完毕后，再继续解析 HTML。</li><li><strong>乱序执行</strong>：多个 <code>async</code> 脚本的执行顺序是<strong>不可预测的</strong>。哪个脚本先下载完，哪个就先执行。<code>scriptB.js</code> 完全有可能在 <code>scriptA.js</code> 之前执行。</li></ol><h4 id="_2-适用场景-1" tabindex="-1">2. 适用场景 <a class="header-anchor" href="#_2-适用场景-1" aria-label="Permalink to &quot;2. 适用场景&quot;">​</a></h4><ul><li>当脚本是完全独立的，不依赖于 DOM，也不依赖于其他任何脚本时。</li><li>例如：网站分析工具、广告脚本、或一些独立的第三方库。</li></ul><h3 id="_1-3-动态创建-script-标签" tabindex="-1">1.3 动态创建 <code>&lt;script&gt;</code> 标签 <a class="header-anchor" href="#_1-3-动态创建-script-标签" aria-label="Permalink to &quot;1.3 动态创建 \`&lt;script&gt;\` 标签&quot;">​</a></h3><p>我们还可以使用 JavaScript 来动态创建一个 <code>&lt;script&gt;</code> 元素并将其添加到文档中，这也是一种实现异步加载的方式。</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 创建一个新的 &lt;script&gt; 标签</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> script</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> document.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">createElement</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;script&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">script.src </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;my-dynamic-script.js&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 将其添加到 &lt;head&gt; 或 &lt;body&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">document.head.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">appendChild</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(script);</span></span></code></pre></div><h4 id="_1-工作方式-2" tabindex="-1">1. 工作方式 <a class="header-anchor" href="#_1-工作方式-2" aria-label="Permalink to &quot;1. 工作方式&quot;">​</a></h4><ul><li>这种方式创建的脚本，其行为在现代浏览器中<strong>类似于 <code>async</code></strong>。脚本的下载和执行都是异步的，下载完成后会立即执行，并且不会保证执行顺序。</li><li>它不会阻塞页面的解析和渲染。</li></ul><h4 id="_2-适用场景-2" tabindex="-1">2. 适用场景 <a class="header-anchor" href="#_2-适用场景-2" aria-label="Permalink to &quot;2. 适用场景&quot;">​</a></h4><ul><li>当你需要根据某些条件或在特定时机才决定是否加载某个脚本时。例如，用户点击某个按钮后才加载一个功能模块。</li></ul><p><strong>总结与对比</strong></p><p>为了让你更清晰地理解它们的区别，这里有一个简单的对比表格：</p><table tabindex="0"><thead><tr><th style="text-align:left;">特性</th><th style="text-align:left;"><code>defer</code></th><th style="text-align:left;"><code>async</code></th><th style="text-align:left;">动态创建</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>下载时是否阻塞</strong></td><td style="text-align:left;">否</td><td style="text-align:left;">否</td><td style="text-align:left;">否</td></tr><tr><td style="text-align:left;"><strong>执行时是否阻塞</strong></td><td style="text-align:left;">否（等到DOM解析完）</td><td style="text-align:left;">是（下载完立即执行）</td><td style="text-align:left;">是（下载完立即执行）</td></tr><tr><td style="text-align:left;"><strong>执行时机</strong></td><td style="text-align:left;">DOM 解析完毕后，<code>DOMContentLoaded</code> 之前</td><td style="text-align:left;">下载完毕后立即执行</td><td style="text-align:left;">下载完毕后立即执行</td></tr><tr><td style="text-align:left;"><strong>执行顺序</strong></td><td style="text-align:left;">按照在 HTML 中的顺序</td><td style="text-align:left;">谁先下载完谁先执行（乱序）</td><td style="text-align:left;">谁先下载完谁先执行（乱序）</td></tr></tbody></table><p><strong>经验法则：</strong></p><ul><li><strong><code>defer</code> 是首选</strong>：它兼顾了性能和可预测的执行顺序，是大多数场景下的最佳选择。</li><li><strong><code>async</code> 用于独立脚本</strong>：当脚本与你的主应用逻辑无关时使用。</li><li><strong>动态创建用于按需加载</strong>：当需要更灵活地控制脚本加载时机时使用。</li></ul>`,33)])])}const f=t(d,[["render",p]]);export{u as __pageData,f as default};
